lessons.solution:
package main
import ("fmt"; "context")
func main() {
    ctx, cancel := context.WithCancel(context.Background())
    defer cancel()
    select {
    case <-ctx.Done():
        fmt.Println("Cancelled")
    default:
        fmt.Println("Running")
    }
}

